/* ============================================================
   IndiaStream — Client-side Configuration
   All tuneable constants live here. Edit this file to change
   ports, proxy URLs, or the source playlist without touching
   application logic in app.js / player.js.
   ============================================================ */

/** IPTV source playlist (used as fallback when working.m3u is missing) */
const CONFIG_PLAYLIST_URL  = 'https://iptv-org.github.io/iptv/index.m3u';

/** Pre-tested, locally cached playlist generated by update_playlist.py */
const CONFIG_LOCAL_WORKING = 'working.m3u';

/** Local CORS proxy — started by run.sh / proxy.py */
const CONFIG_LOCAL_PROXY   = 'http://localhost:8081/proxy?url=';

/** Remote CORS proxy fallback (used when local proxy is not reachable) */
const CONFIG_REMOTE_PROXY  = 'https://corsproxy.io/?url=';
